	ObjectIdResolver resolver = null;

	if (_objectIdResolvers == null) {
		_objectIdResolvers = new ArrayList<ObjectIdResolver>(8);
	} else {
		for (ObjectIdResolver res : _objectIdResolvers) {
			if (res.canUseFor(resolverType)) {
